import{_ as t,a as e,b as d,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as n,o as c,c as p,a2 as u}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Резервное дублирование и переключение источника чтения","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Other/redundant-backup-and-read-source.md","filePath":"ru-RU/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),h={name:"ru-RU/Other/redundant-backup-and-read-source.md"};function l(o,a,i,s,b,k){return c(),p("div",null,[...a[0]||(a[0]=[u('<h1 id="резервное-дублирование-и-переключение-источника-чтения" tabindex="-1">Резервное дублирование и переключение источника чтения <a class="header-anchor" href="#резервное-дублирование-и-переключение-источника-чтения" aria-label="Permalink to &quot;Резервное дублирование и переключение источника чтения&quot;">​</a></h1><p>Redundant backup сохраняет дополнительную копию уже загруженного файла.</p><p>И основной файл, и backup file могут использоваться как read sources. Для посетителей обычно нет разницы. Отличается только storage channel, из которого отдается файл.</p><h2 id="что-умеет-redundant-backup" tabindex="-1">Что умеет Redundant Backup <a class="header-anchor" href="#что-умеет-redundant-backup" aria-label="Permalink to &quot;Что умеет Redundant Backup&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Возможность</th><th>Описание</th></tr></thead><tbody><tr><td>Хранить дополнительную копию</td><td>Резервирует файлы в другой upload channel, чтобы снизить риск отказа одного канала.</td></tr><tr><td>Переключать read source</td><td>После успешного backup переключает чтение файла между primary channel и backup channel.</td></tr><tr><td>Single-file backup</td><td>Резервирует один файл со страницы деталей файла.</td></tr><tr><td>Batch backup</td><td>Выбирает несколько файлов в админ-панели и резервирует их вместе.</td></tr><tr><td>Global redundant backup</td><td>Резервирует файлы по папке из Other Settings.</td></tr></tbody></table><h2 id="вход-redundant-backup" tabindex="-1">Вход Redundant Backup <a class="header-anchor" href="#вход-redundant-backup" aria-label="Permalink to &quot;Вход Redundant Backup&quot;">​</a></h2><p>Откройте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+t+'" alt="Redundant backup" loading="lazy"></p><p>Этот вход лучше всего подходит для массового добавления backup к папке или ко всем файлам.</p><p>Backup channel можно выбрать вручную, либо включить automatic switching и позволить ImgBed найти подходящий backup channel.</p><h2 id="backup-со-страницы-деталеи-фаила" tabindex="-1">Backup со страницы деталей файла <a class="header-anchor" href="#backup-со-страницы-деталеи-фаила" aria-label="Permalink to &quot;Backup со страницы деталей файла&quot;">​</a></h2><p>Откройте страницу деталей файла в админ-панели и нажмите backup.</p><p><img src="'+e+'" alt="Backup в деталях файла" loading="lazy"></p><p>Это лучше всего подходит для резервирования одного важного файла по запросу.</p><p>После успешного backup страница деталей файла показывает доступные read sources.</p><h2 id="batch-backup-по-выбору" tabindex="-1">Batch Backup по выбору <a class="header-anchor" href="#batch-backup-по-выбору" aria-label="Permalink to &quot;Batch Backup по выбору&quot;">​</a></h2><p>В админ-панели выберите несколько файлов и запустите batch backup.</p><p><img src="'+d+'" alt="Batch backup" loading="lazy"></p><p>Это удобно для обработки группы файлов.</p><p>Selection backup, file details backup и redundant backup в Other Settings используют одну и ту же backup system. Это просто разные точки входа.</p><h2 id="переключение-read-source-после-backup" tabindex="-1">Переключение Read Source после backup <a class="header-anchor" href="#переключение-read-source-после-backup" aria-label="Permalink to &quot;Переключение Read Source после backup&quot;">​</a></h2><p>После завершения backup страница деталей файла позволяет переключить read source:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Описание</th></tr></thead><tbody><tr><td>Primary channel</td><td>Чтение из исходного upload channel.</td></tr><tr><td>Backup channel</td><td>Чтение из backup channel.</td></tr></tbody></table><p><img src="'+r+'" alt="Переключение read source после backup" loading="lazy"></p><p>Посетителям не нужно знать, отдается ли файл из primary или backup channel.</p><p>Выбранный read source становится предпочтительным для дальнейшего доступа к файлу.</p><h2 id="когда-backup-пропускается" tabindex="-1">Когда Backup пропускается <a class="header-anchor" href="#когда-backup-пропускается" aria-label="Permalink to &quot;Когда Backup пропускается&quot;">​</a></h2><p>При backup такие случаи пропускаются. Это не ошибки.</p><table tabindex="0"><thead><tr><th>Случай</th><th>Почему пропускается</th></tr></thead><tbody><tr><td>Already backed up</td><td>Файл, у которого уже есть backup, не резервируется повторно.</td></tr><tr><td>Primary and backup channels are the same</td><td>Backup должен храниться в другом channel, иначе он не имеет смысла.</td></tr><tr><td>No usable backup channel</td><td>Нет подходящего альтернативного channel.</td></tr></tbody></table><p>Коротко: backups должны идти в другой channel, а уже зарезервированные файлы не тратят место повторно.</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Название</th><th>Значение</th></tr></thead><tbody><tr><td>Primary channel</td><td>Channel, через который файл был загружен впервые.</td></tr><tr><td>Backup channel</td><td>Channel, где хранится redundant copy.</td></tr><tr><td>Primary read source</td><td>Файл сейчас читается из primary channel.</td></tr><tr><td>Backup read source</td><td>Файл сейчас читается из backup channel.</td></tr></tbody></table><p>Primary и backup read sources ведут себя одинаково для пользователя.</p><p>Пока backup file доступен, изображения, видео и download links продолжают работать после переключения на backup read source.</p><h2 id="что-происходит-при-удалении-фаила" tabindex="-1">Что происходит при удалении файла <a class="header-anchor" href="#что-происходит-при-удалении-фаила" aria-label="Permalink to &quot;Что происходит при удалении файла&quot;">​</a></h2><p>Когда файл удаляется, ImgBed удаляет и primary file, и backup file.</p>',37)])])}const B=n(h,[["render",l]]);export{_ as __pageData,B as default};
